```aether:src/utils/eventEmitter.ts
import { EventMap } from '../types';

type EventKey = keyof EventMap;
type EventListener<K extends EventKey> = (payload: EventMap[K]) => void;

class EventEmitter {
  private listeners: { [K in EventKey]?: EventListener<K>[] } = {};

  on<K extends EventKey>(eventName: K, listener: EventListener<K>): void {
    if (!this.listeners[eventName]) {
      this.listeners[eventName] = [];
    }
    this.listeners[eventName]!.push(listener);
  }

  emit<K extends EventKey>(eventName: K, payload: EventMap[K]): void {
    const eventListeners = this.listeners[eventName];
    if (eventListeners) {
      eventListeners.forEach(listener => listener(payload));
    }
  }
}

export const eventEmitter = new EventEmitter();
