```aether:src/services/teamService.ts
import { db } from '../db';
import { eventEmitter } from '../utils/eventEmitter';
import { Team } from '../types';
import { v4 as uuidv4 } from 'uuid';

export class TeamService {
  async createTeam(name: string, ownerId: string): Promise<Team> {
    if (!name || name.trim() === '') {
      throw new Error('Team name cannot be empty.');
    }
    if (!ownerId) {
      throw new Error('Owner ID is required to create a team.');
    }

    const newTeamId = uuidv4();

    const newTeam: Team = {
      id: newTeamId,
      name,
      ownerId,
    };

    // 1. Create the team
    await db.teams.create(newTeam);

    // 2. Add the caller as the owner to team_members
    await db.teamMembers.add({
      teamId: newTeamId,
      userId: ownerId,
      role: 'owner',
    });

    // 3. Emit team.created event
    eventEmitter.emit('team.created', {
      teamId: newTeamId,
      teamName: name,
      ownerId,
    });

    return newTeam;
  }
}

export const teamService = new TeamService();
