import { Hono } from 'hono';
import { teamService } from '../services/teamService';

// Define a type for the Hono context variables
type Variables = {
  userId: string; // This will be set by a middleware, simulating authentication
};

const teams = new Hono<{ Variables: Variables }>();

teams.post('/', async (c) => {
  const { name } = await c.req.json();
  const ownerId = c.get('userId'); // Get ownerId from context (set by auth middleware)

  if (!ownerId) {
    return c.json({ error: 'Authentication required. User ID not found in context.' }, 401);
  }

  try {
    const newTeam = await teamService.createTeam(name, ownerId);
    return c.json(newTeam, 201);
  } catch (error: any) {
    console.error('Error creating team:', error);
    if (error.message.includes('Team name cannot be empty') || error.message.includes('Owner ID is required')) {
      return c.json({ error: error.message }, 400);
    }
    return c.json({ error: 'Failed to create team.' }, 500);
  }
});

export default teams;
```

```aether:src/index.ts
import { Hono } from 'hono';
import { logger } from 'hono/logger';
import { prettyJSON } from 'hono/pretty-json';
import { v4 as uuidv4 } from 'uuid';

import teamsRouter from './routes/teams';
import { eventEmitter } from './utils/eventEmitter';

const app = new Hono();

// Middlewares
app.use(logger()); // Logs requests to the console
app.use(prettyJSON()); // Formats JSON responses nicely

// Mock authentication middleware
// In a real app, this would parse a JWT or session to get the user ID
app.use('*', async (c, next) => {
  // For demonstration, we'll just set a static user ID or generate one
  // In a real scenario, this would come from an authenticated session/token
  const mockUserId = 'user-' + uuidv4().split('-')[0]; // Example: user-xxxx
  c.set('userId', mockUserId);
  await next();
});

// Register routes
app.route('/teams', teamsRouter);

// Event Listener for team.created
eventEmitter.on('team.created', (event) => {
  console.log(`[EVENT] Team Created:`, event);
  // In a real application, this might trigger:
  // - Sending a notification to the owner
  // - Updating a search index
  // - Logging to an analytics service
});

// Default route
app.get('/', (c) => {
  return c.text('Welcome to the Team Management API!');
});

// Error handling
app.onError((err, c) => {
  console.error(`${err}`);
  return c.json({ error: 'Internal Server Error' }, 500);
});

// Start the server
const port = 3000;
console.log(`Server is running on http://localhost:${port}`);

export default {
  port,
  fetch: app.fetch,
};
